import React from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate, Outlet } from 'react-router-dom';
import Layout from './components/Layout';
import HomePage from './components/HomePage';
import PleadingsPage from './components/PleadingsPage';
import MotionsPage from './components/MotionsPage';
import FormsPage from './components/FormsPage';
import ResourcesPage from './components/ResourcesPage';
import Login from './components/Login';
import { ThemeProvider } from './context/ThemeContext';
import { AuthProvider } from './context/AuthContext';
import ProtectedRoute from './components/ProtectedRoute';
import DeclarationRoutes from './routes/DeclarationRoutes';
import PleadingsRoutes from './routes/PleadingsRoutes';

function App() {
  return (
    <AuthProvider>
      <ThemeProvider>
        <Router>
          <Routes>
            <Route path="/login" element={<Login />} />

            {/* Root route redirects to home if authenticated, login if not */}
            <Route 
              path="/" 
              element={
                <ProtectedRoute>
                  <Navigate to="/home" replace />
                </ProtectedRoute>
              } 
            />

            {/* Protected routes wrapped in Layout */}
            <Route
              element={
                <ProtectedRoute>
                  <Layout>
                    <Outlet />
                  </Layout>
                </ProtectedRoute>
              }
            >
              <Route path="/home" element={<HomePage />} />
              <Route path="/pleadings/*" element={<PleadingsRoutes />} />
              <Route path="/motions" element={<MotionsPage />} />
              <Route path="/forms" element={<FormsPage />} />
              <Route path="/resources/*" element={<ResourcesPage />} />
              <Route path="/declaration/*" element={<DeclarationRoutes />} />
            </Route>
          </Routes>
        </Router>
      </ThemeProvider>
    </AuthProvider>
  );
}

export default App;
